(function () {
  'use strict';

  const doc = document;
  const body = doc.body;
  const root = doc.documentElement;
  const userAgent = navigator.userAgent;

  const IS_IE_OR_EDGE = /Trident|Edge/.test(userAgent);
  const TARGET_INPUT_TYPES = { text: 1, password: 1, number: 1, url: 1, email: 1, tel: 1, search: 1 };
  const EXTRA_MARGIN = { number: IS_IE_OR_EDGE || /Mobile|Android/.test(userAgent) ? 15 : 0, password: IS_IE_OR_EDGE ? 15 : 0 };

  const clearIcon = doc.createElement('input-clear-icon');
  clearIcon.style.display = 'none';
  clearIcon.onmousedown = e => e.preventDefault(); // focus engelle
  body.appendChild(clearIcon);

  let clearTargetElement;
 
  clearIcon.onclick = () => {
    if (!clearTargetElement) return;

    clearTargetElement.value = '';
    clearTargetElement.dispatchEvent(new Event('input', { bubbles: true }));
    clearTargetElement.dispatchEvent(new Event('change', { bubbles: true }));
    clearTargetElement.focus();
	clearTargetElement.autocomplete();
  };

  function updateIconPosition(input) {
    const rect = input.getBoundingClientRect();
    const style = getComputedStyle(input);
    const iconStyle = clearIcon.style;

    iconStyle.display = 'inline-block';
    iconStyle.fontSize = style.fontSize;
    iconStyle.zIndex = (parseInt(style.zIndex, 10) || 1) + 1;
    iconStyle.top = root.scrollTop + body.scrollTop + rect.top + (rect.height - parseInt(style.fontSize)) / 2 + 'px';
    iconStyle.left = root.scrollLeft + body.scrollLeft + rect.right
      - parseInt(style.borderRightWidth)
      - parseInt(style.paddingRight)
      - (EXTRA_MARGIN[input.type] || 0)
      - 16 + 'px';

    clearIcon.className = input.dataset.inputClearIconClass || '';
    applyStyles(iconStyle, input.dataset.inputClearIconStyle);
  }

  function listener(e) {
    const el = e.target;
    if (el.tagName !== 'INPUT' || !TARGET_INPUT_TYPES[el.type] || el.hasAttribute('data-input-clear-icon-hidden')) return;

    const hasValue = el.value || (el.validity || {}).badInput;
    const isActive = doc.activeElement === el && !el.readOnly && !el.disabled;

    if (hasValue && isActive) {
      if (clearTargetElement !== el) {
        clearTargetElement = el;
        updateIconPosition(el);
      }
    } else {
      clearIcon.style.display = 'none';
      clearTargetElement = undefined;
    }
  }

  function applyStyles(styleObj, styleString) {
    if (!styleString) return;
    styleString.split(';').forEach(entry => {
      const [key, value] = entry.split(':');
      if (key && value) styleObj[camel(key.trim())] = value.trim();
    });
  }

  function camel(str) {
    return str.replace(/-([a-z])/g, (_, c) => c.toUpperCase());
  }

  addEventListener('focus', listener, true);
  addEventListener('input', listener, true);
  addEventListener('blur', listener, true);
})();